import { useUserSession } from "@/hooks/use-user-session";
import { getRouteApi } from "@tanstack/react-router";
import {
  AnedotTypemarkIcon,
  Button,
  cn,
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  Sidebar,
  SidebarContent,
  SidebarHeader,
  SidebarTrigger,
  useSidebar,
} from "@workspace/ui";
import { Check, ChevronsUpDown } from "lucide-react";

const authedRouteApi = getRouteApi("/_authed");

export function AppSidebar({ className }: { className?: string }) {
  const { tenants, currentTenant } = authedRouteApi.useLoaderData();
  const { setSelectedTenantId, isPending } = useUserSession();
  const { collapsed } = useSidebar();

  const tenantLabel = currentTenant?.name ?? "Select tenant";
  const switcherAriaLabel = collapsed
    ? `Switch organization, current: ${tenantLabel}`
    : "Switch organization";

  return (
    <Sidebar
      className={cn("shrink-0 border-sidebar-border bg-sidebar", className)}
      collapsible="icon"
    >
      <SidebarHeader>
        {tenants.length === 0 ? (
          <p className="px-2 text-muted-foreground text-sm leading-snug">
            No tenants yet
          </p>
        ) : (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                aria-label={switcherAriaLabel}
                className={cn(
                  "h-10 shrink-0 font-normal",
                  collapsed
                    ? "size-10 justify-center p-0"
                    : "w-full min-w-0 justify-between gap-2 px-2",
                )}
                disabled={isPending}
                title={collapsed ? tenantLabel : undefined}
                variant="outline"
              >
                <AnedotTypemarkIcon
                  className={cn(
                    "shrink-0 text-secondary-600",
                    collapsed ? "h-7 w-auto" : "h-5 w-auto",
                  )}
                  size={collapsed ? 28 : 22}
                />
                {!collapsed ? (
                  <>
                    <span className="min-w-0 flex-1 truncate text-left text-sm">
                      {tenantLabel}
                    </span>
                    <ChevronsUpDown className="size-4 shrink-0 opacity-60" />
                  </>
                ) : null}
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent
              align="start"
              className={cn(
                "min-w-56 border-border bg-popover text-popover-foreground",
              )}
              side={collapsed ? "right" : "bottom"}
              sideOffset={collapsed ? 8 : 4}
            >
              {tenants.map((tenant) => (
                <DropdownMenuItem
                  className="cursor-pointer gap-2 text-foreground focus:bg-accent focus:text-accent-foreground"
                  disabled={isPending}
                  key={tenant.id}
                  onSelect={() => {
                    void setSelectedTenantId(tenant.id);
                  }}
                >
                  <span className="min-w-0 flex-1 truncate">{tenant.name}</span>
                  {currentTenant?.id === tenant.id ? (
                    <Check className="size-4 shrink-0 text-primary" />
                  ) : null}
                </DropdownMenuItem>
              ))}
            </DropdownMenuContent>
          </DropdownMenu>
        )}
      </SidebarHeader>
      <SidebarContent className="min-h-0 flex-1" />
      <div className="border-sidebar-border border-t p-2">
        <div className="flex justify-end">
          <SidebarTrigger />
        </div>
      </div>
    </Sidebar>
  );
}

