import { useUserSession } from "@/hooks/use-user-session";
import { getTenantInitials } from "@/lib/tenant-initials";
import { getRouteApi } from "@tanstack/react-router";
import {
  cn,
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  Sidebar,
  SidebarContent,
  SidebarHeader,
  SidebarMenuButton,
  SidebarTrigger,
  useSidebar,
} from "@workspace/ui";
import { Check, ChevronsUpDown } from "lucide-react";

const authedRouteApi = getRouteApi("/_authed");

const tenantLogoClasses =
  "flex size-8 shrink-0 items-center justify-center rounded-md bg-secondary-600 font-bold text-white text-xs";

export function AppSidebar({ className }: { className?: string }) {
  const { tenants, currentTenant } = authedRouteApi.useLoaderData();
  const { setSelectedTenantId, isPending } = useUserSession();
  const { collapsed } = useSidebar();

  const tenantLabel = currentTenant?.name ?? "Select tenant";
  const tenantInitials = currentTenant
    ? getTenantInitials(currentTenant.name)
    : "?";
  const switcherAriaLabel = collapsed
    ? `Switch organization, current: ${tenantLabel}`
    : "Switch organization";

  return (
    <Sidebar
      className={cn("shrink-0 border-sidebar-border bg-sidebar", className)}
      collapsible="icon"
    >
      <SidebarHeader className="p-0 transition-none">
        <div className="border-sidebar-border border-b px-2 py-2">
          {tenants.length === 0 ? (
            <p className="text-muted-foreground text-sm leading-snug">
              No tenants yet
            </p>
          ) : (
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <SidebarMenuButton
                  aria-label={switcherAriaLabel}
                  className={cn(
                    "h-10 w-full gap-2 text-sidebar-foreground shadow-none ring-0",
                    "hover:bg-sidebar-accent/80 data-[state=open]:bg-sidebar-accent/90",
                    "focus-visible:ring-0 focus-visible:ring-offset-0",
                    "dark:hover:bg-sidebar-accent/50",
                  )}
                  disabled={isPending}
                  size="md"
                  title={collapsed ? tenantLabel : undefined}
                  variant="default"
                >
                  <div aria-hidden className={tenantLogoClasses}>
                    {tenantInitials}
                  </div>
                  {!collapsed ? (
                    <>
                      <span className="min-w-0 flex-1 truncate text-left font-semibold text-sidebar-foreground text-sm">
                        {tenantLabel}
                      </span>
                      <ChevronsUpDown className="size-4 shrink-0 text-sidebar-foreground/50" />
                    </>
                  ) : null}
                </SidebarMenuButton>
              </DropdownMenuTrigger>
              <DropdownMenuContent
                align="start"
                className={cn(
                  "min-w-56 border-border bg-popover text-popover-foreground",
                )}
                side={collapsed ? "right" : "bottom"}
                sideOffset={collapsed ? 8 : 4}
              >
                {tenants.map((tenant) => (
                  <DropdownMenuItem
                    className="cursor-pointer gap-2 text-foreground focus:bg-accent focus:text-accent-foreground"
                    disabled={isPending}
                    key={tenant.id}
                    onSelect={() => {
                      void setSelectedTenantId(tenant.id);
                    }}
                  >
                    <span className="min-w-0 flex-1 truncate">{tenant.name}</span>
                    {currentTenant?.id === tenant.id ? (
                      <Check className="size-4 shrink-0 text-primary" />
                    ) : null}
                  </DropdownMenuItem>
                ))}
              </DropdownMenuContent>
            </DropdownMenu>
          )}
        </div>
      </SidebarHeader>
      <SidebarContent className="min-h-0 flex-1" />
      <div
        className={cn(
          "border-sidebar-border border-t py-2",
          collapsed ? "px-1" : "px-2",
        )}
      >
        <div className="flex items-center justify-end">
          <SidebarTrigger className="size-10 shrink-0" />
        </div>
      </div>
    </Sidebar>
  );
}
